<section class="page-heading split"><div><span class="eyebrow blue">Gestão de conteúdo</span><h1>Vídeos de treinamento</h1><p>Publique vídeos próprios ou reutilize conteúdos oficiais do YouTube e defina exatamente quem poderá encontrá-los.</p></div><?php if(can('videos','create')): ?><button class="btn primary" data-video-create><i class="bi bi-plus-lg"></i> Novo vídeo</button><?php endif; ?></section>
<?php if($flash): ?><div class="alert <?= $flash['type']==='success'?'success':'error' ?>"><i class="bi <?= $flash['type']==='success'?'bi-check-circle':'bi-exclamation-circle' ?>"></i> <?= e($flash['message']) ?></div><?php endif; ?>
<section class="panel">
<form class="panel-head table-filters video-filters" method="get" action="<?= url('videos') ?>"><div class="search"><span><i class="bi bi-search"></i></span><input type="search" name="q" value="<?= e($q) ?>" placeholder="Buscar título ou descrição..."></div><div class="panel-filters"><select name="categoria"><option value="">Todas as categorias</option><?php foreach($categoryOptions as $option): ?><option value="<?= (int)$option['id'] ?>" <?= $categoryFilter===(int)$option['id']?'selected':'' ?>><?= e($option['nome']) ?></option><?php endforeach; ?></select><select name="tipo"><option value="">Todas as origens</option><option value="upload" <?= $typeFilter==='upload'?'selected':'' ?>>Arquivo próprio</option><option value="youtube" <?= $typeFilter==='youtube'?'selected':'' ?>>YouTube</option></select><select name="status"><option value="">Todas as situações</option><option value="publicado" <?= $status==='publicado'?'selected':'' ?>>Publicados</option><option value="rascunho" <?= $status==='rascunho'?'selected':'' ?>>Rascunhos</option><option value="arquivado" <?= $status==='arquivado'?'selected':'' ?>>Arquivados</option></select><button class="btn secondary"><i class="bi bi-search"></i> Buscar</button><?php if($q!==''||$status!==''||$typeFilter!==''||$categoryFilter): ?><a class="btn secondary" href="<?= url('videos') ?>" aria-label="Limpar filtros"><i class="bi bi-x-lg"></i></a><?php endif; ?></div></form>
<div class="table-wrap"><table><thead><tr><th>Vídeo</th><th>Organização</th><th>Veículos vinculados</th><th>Origem</th><th>Visualizações</th><th>Situação</th><th>Ações</th></tr></thead><tbody>
<?php if(!$videos): ?><tr><td colspan="7"><div class="table-empty"><i class="bi bi-camera-video"></i><strong>Nenhum vídeo encontrado</strong><span>Cadastre um arquivo próprio ou adicione um vídeo do YouTube.</span></div></td></tr><?php endif; ?>
<?php foreach($videos as $video): ?><?php $thumb=$video['thumbnail']?(str_starts_with($video['thumbnail'],'http')?$video['thumbnail']:url($video['thumbnail'])):'';$playUrl=$video['tipo']==='upload'?url($video['arquivo_url']):$video['arquivo_url'];$familyIds=array_values(array_filter(explode(',',(string)$video['familia_ids'])));$modelIds=array_values(array_filter(explode(',',(string)$video['modelo_ids']))); ?>
<tr><td><div class="entity-cell video-entity"><?php if($thumb): ?><img src="<?= e($thumb) ?>" alt="Capa de <?= e($video['titulo']) ?>"><?php else: ?><span class="entity-placeholder"><i class="bi bi-play-btn"></i></span><?php endif; ?><div><strong><?= e($video['titulo']) ?></strong><small><?= $video['duracao_segundos']?floor($video['duracao_segundos']/60).' min':'Duração não informada' ?></small></div></div></td><td><span class="pill"><?= e($video['categoria_nome']) ?></span><small><?= e($video['subcategoria_nome']?:'Sem subcategoria') ?></small></td><td class="description-cell"><strong><?= e($video['familias_nomes']?:'Conteúdo geral') ?></strong><small><?= e($video['modelos_nomes']?:'Todos os modelos das famílias') ?></small></td><td><span class="source-badge <?= $video['tipo'] ?>"><i class="bi <?= $video['tipo']==='youtube'?'bi-youtube':'bi-cloud-arrow-up' ?>"></i> <?= $video['tipo']==='youtube'?'YouTube':'Arquivo próprio' ?></span></td><td><?= (int)$video['visualizacoes'] ?></td><td><span class="status <?= $video['status']==='publicado'?'active':($video['status']==='arquivado'?'inactive':'draft') ?>"><?= e(ucfirst($video['status'])) ?></span></td><td><div class="row-actions"><button class="action-btn" data-video-preview data-title="<?= e($video['titulo']) ?>" data-type="<?= e($video['tipo']) ?>" data-url="<?= e($playUrl) ?>" aria-label="Visualizar <?= e($video['titulo']) ?>"><i class="bi bi-play-fill"></i></button><?php if(can('videos','update')): ?><button class="action-btn" data-video-edit data-id="<?= (int)$video['id'] ?>" data-title="<?= e($video['titulo']) ?>" data-description="<?= e($video['descricao']) ?>" data-category="<?= (int)$video['categoria_id'] ?>" data-subcategory="<?= (int)($video['subcategoria_id']??0) ?>" data-type="<?= e($video['tipo']) ?>" data-youtube="<?= $video['tipo']==='youtube'?e($video['arquivo_url']):'' ?>" data-duration="<?= $video['duracao_segundos']?(int)ceil($video['duracao_segundos']/60):'' ?>" data-status="<?= e($video['status']) ?>" data-thumbnail="<?= e($thumb) ?>" data-families="<?= e(json_encode($familyIds)) ?>" data-models="<?= e(json_encode($modelIds)) ?>" aria-label="Editar <?= e($video['titulo']) ?>"><i class="bi bi-pencil"></i></button><?php endif; ?><?php if(can('videos','delete')): ?><button class="action-btn danger" data-video-delete data-id="<?= (int)$video['id'] ?>" data-name="<?= e($video['titulo']) ?>" aria-label="Excluir <?= e($video['titulo']) ?>"><i class="bi bi-trash"></i></button><?php endif; ?></div></td></tr>
<?php endforeach; ?></tbody></table></div>
<div class="pagination"><form method="get" action="<?= url('videos') ?>" class="per-page"><input type="hidden" name="q" value="<?= e($q) ?>"><input type="hidden" name="status" value="<?= e($status) ?>"><input type="hidden" name="tipo" value="<?= e($typeFilter) ?>"><input type="hidden" name="categoria" value="<?= $categoryFilter?:'' ?>"><label>Mostrar <select name="per_page" onchange="this.form.submit()"><?php foreach([5,10,25,50] as $size): ?><option value="<?= $size ?>" <?= $perPage===$size?'selected':'' ?>><?= $size ?></option><?php endforeach; ?></select> linhas</label></form><span>Mostrando <?= $totalRows?$offset+1:0 ?>–<?= min($offset+$perPage,$totalRows) ?> de <?= $totalRows ?></span><nav class="page-buttons" aria-label="Paginação"><?php if($page>1): ?><a href="<?= page_url('videos',['page'=>$page-1]) ?>"><i class="bi bi-chevron-left"></i></a><?php endif; ?><?php for($p=max(1,$page-2);$p<=min($totalPages,$page+2);$p++): ?><a class="<?= $p===$page?'active':'' ?>" href="<?= page_url('videos',['page'=>$p]) ?>"><?= $p ?></a><?php endfor; ?><?php if($page<$totalPages): ?><a href="<?= page_url('videos',['page'=>$page+1]) ?>"><i class="bi bi-chevron-right"></i></a><?php endif; ?></nav></div>
</section>

